/* global Office, document */

Office.onReady((info) => {
  if (info.host === Office.HostType.Outlook) {
    const sideloadMsg = document.getElementById("sideload-msg");
    const appBody = document.getElementById("app-body");
    const runBtn = document.getElementById("run");

    if (sideloadMsg) sideloadMsg.style.display = "none";
    if (appBody) appBody.style.display = "flex";
    if (runBtn) {
      runBtn.onclick = run;
    }
  }
});

export async function run() {
  try {
    const item = Office.context.mailbox.item;

    const data = {
      metadata: {
        sourceMessageId: item.internetMessageId || "",
        subject: item.subject || "",
        user: Office.context.mailbox.userProfile.emailAddress
      },
      recipients: {
        to: item.to ? item.to.map(r => r.emailAddress) : [],
        cc: item.cc ? item.cc.map(r => r.emailAddress) : []
      }
    };

    console.log("CSAT DATA:", data);

    await fetch("https://default3602aff1a179420eb9e6867ac2486b.86.environment.api.powerplatform.com:443/powerautomate/automations/direct/workflows/47e4bbe0e3ae44188b71d05113d12505/triggers/manual/paths/invoke?api-version=1&sp=%2Ftriggers%2Fmanual%2Frun&sv=1.0&sig=wOV3rtYjdhN2jI3Hr2e9fe5XhzfuuaNjW_R1u9giGO0", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(data)
    });

    const insertAt = document.getElementById("item-subject");
    if (insertAt) {
      insertAt.innerHTML = `
<pre>✅ Enviado al flow correctamente</pre>
`;
    }
  } catch (error) {
    console.error("Error:", error);

    const insertAt = document.getElementById("item-subject");
    if (insertAt) {
      insertAt.innerHTML = `
<pre>❌ Error: ${error.message}</pre>
`;
    }
  }
}